css:
.loader { --speed: var(--loader-speed); --accent: var(--loader-color); --accent-2: var(--loader-secondary-color); width: var(--loader-size); height: var(--loader-size); display: grid; place-items: center; position: relative; perspective: 550px; }
.cube { width: 44%; height: 44%; position: relative; transform-style: preserve-3d; animation: holo-turn calc(var(--speed) * 3) linear infinite; }
.cube i, .cube::before, .cube::after { content: ""; position: absolute; inset: 0; border: 2px solid var(--accent); background: color-mix(in srgb, var(--accent) 12%, transparent); box-shadow: inset 0 0 18px color-mix(in srgb, var(--accent-2) 45%, transparent), 0 0 16px var(--accent); }
.cube::before { transform: rotateY(90deg) translateZ(calc(var(--loader-size) * .22)); } .cube::after { transform: rotateX(90deg) translateZ(calc(var(--loader-size) * .22)); }
.cube i:nth-child(1) { transform: translateZ(calc(var(--loader-size) * .22)); } .cube i:nth-child(2) { transform: translateZ(calc(var(--loader-size) * -.22)); } .cube i:nth-child(3) { transform: rotateY(90deg) translateZ(calc(var(--loader-size) * -.22)); }
.scan { position: absolute; width: 74%; height: 5%; border-radius: 999px; background: var(--accent-2); box-shadow: 0 0 18px 4px var(--accent-2); animation: holo-scan calc(var(--speed) * 1.6) ease-in-out infinite; }
@keyframes holo-turn { to { transform: rotateX(360deg) rotateY(360deg); } }
@keyframes holo-scan { 0%,100% { transform: translateY(calc(var(--loader-size) * -.36)); opacity: .25; } 50% { transform: translateY(calc(var(--loader-size) * .36)); opacity: 1; } }
